	"net/url"

	"golang.org/x/oauth2"
)

var OAuthConfig = &oauth2.Config{
	ClientID:     "your-client-id",
	ClientSecret: "your-client-secret",
	RedirectURL:  "https://yourapp.com/callback",
	Scopes:       []string{"openid", "profile", "email"},
	Endpoint: oauth2.Endpoint{
		AuthURL:  "https://provider.com/oauth2/authorize",
		TokenURL: "https://provider.com/oauth2/token",
	},
}

// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// 1. Fix CSRF: Generate a cryptographically secure random state.
	// A unique state for every request prevents CSRF and state-fixation attacks.
	b := make([]byte, 32)
	if _, err := rand.Read(b); err != nil {
		return "", fmt.Errorf("failed to generate random state: %w", err)
	}
	state := base64.URLEncoding.EncodeToString(b)

	// 2. Fix Open Redirect: Validate and resolve the user-provided redirectPath.
	// We ensure the final redirect URL matches the host and scheme of our configured RedirectURL.
	config := *OAuthConfig
	if redirectPath != "" {
		base, err := url.Parse(OAuthConfig.RedirectURL)
		if err != nil {
			return "", fmt.Errorf("invalid base redirect configuration: %w", err)
		}

		provided, err := url.Parse(redirectPath)
		if err != nil {
			return "", fmt.Errorf("invalid redirect path: %w", err)
		}

		// ResolveReference handles both relative paths (e.g., "/callback/custom") 
		// and absolute URLs, allowing us to verify the final destination.
		resolved := base.ResolveReference(provided)

		// Security check: Ensure the host and scheme have not been tampered with.
		if resolved.Host != base.Host || resolved.Scheme != base.Scheme {
			return "", fmt.Errorf("unauthorized redirect URL: %s", redirectPath)
		}
		config.RedirectURL = resolved.String()
	}

	// 3. Generate the authorization URL using the secure state.
	authURL := config.AuthCodeURL(state)

	// 4. Secure Cookie Management: Store the state in a secure, short-lived cookie.
	// HttpOnly prevents XSS access, Secure ensures HTTPS, and MaxAge limits the attack window.
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		Path:     "/",
		HttpOnly: true,
		Secure:   true, // Ensure your application uses HTTPS in production
		SameSite: http.SameSiteLaxMode,
		MaxAge:   600, // State expires in 10 minutes
	})

	return authURL, nil
}

