	// 2. Fix Open Redirect: Validate the user-provided redirectPath.
	// We must ensure the redirect URL stays within our authorized domain.
	base, err := url.Parse(OAuthConfig.RedirectURL)
	if err != nil {
		return "", fmt.Errorf("invalid base configuration: %w", err)
	}

