	config := *OAuthConfig
	config.RedirectURL = validatedRedirectURL

	// Generate the authorization URL.
	authURL := config.AuthCodeURL(state)

	// 3. Secure Cookie: Store the state in a secure, HttpOnly cookie.
	// This will be verified in the callback handler to prevent CSRF.
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,
		Secure:   true, // Should be true in production (requires HTTPS)
		SameSite: http.SameSiteLaxMode,
		Path:     "/",
		MaxAge:   600, // State should be short-lived (e.g., 10 minutes)
