// It fixes security issues by generating a random state and validating the redirect path.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// 1. Security Fix: Generate a cryptographically secure random state to prevent CSRF.
	// The state must be unique per request and verified in the callback handler.
	b := make([]byte, 16)
	if _, err := rand.Read(b); err != nil {
		return "", err
	}
	state := hex.EncodeToString(b)

	// 2. Security Fix: Validate the user-provided redirectPath to prevent Open Redirect vulnerabilities.
	// We ensure the redirectPath is resolved against our base RedirectURL and matches the authorized host/scheme.
	baseRedirect, err := url.Parse(OAuthConfig.RedirectURL)
	if err != nil {
		return "", err
	}

	parsedRedirect, err := url.Parse(redirectPath)
	if err != nil {
		return "", err
	}

	// Resolve the provided path against the base RedirectURL. This handles both relative paths and absolute URLs.
	resolvedURL := baseRedirect.ResolveReference(parsedRedirect)

	// Ensure the resolved URL matches the host and scheme of our registered callback.
	// This prevents attackers from redirecting the OAuth code to an external domain.
	if resolvedURL.Host != baseRedirect.Host || resolvedURL.Scheme != baseRedirect.Scheme {
		return "", errors.New("invalid redirect URL: host or scheme mismatch")
	}

	// Create a copy of the OAuth config with the validated custom redirect URL
	config := *OAuthConfig
	config.RedirectURL = resolvedURL.String()

	// Generate the authorization URL
	authURL := config.AuthCodeURL(state)

	// 3. Security Fix: Set the state in a secure cookie for later validation.
	// We use HttpOnly to prevent XSS access, Secure for HTTPS-only transmission,
	// and SameSite=Lax to allow the cookie to be sent after the provider redirect.
	if w != nil {
		http.SetCookie(w, &http.Cookie{
			Name:     "oauth_state",
			Value:    state,
			HttpOnly: true,
			Secure:   true, // Should be true in production to ensure HTTPS
			SameSite: http.SameSiteLaxMode,
			Path:     "/",
			MaxAge:   600, // 10-minute expiration for the state
		})
	}

	return authURL, nil
