func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// 1. Secure State Generation
	// Use a cryptographically secure random generator to prevent CSRF.
	b := make([]byte, 16)
	if _, err := rand.Read(b); err != nil {
		return "", err
	}
	state := hex.EncodeToString(b)

	// 2. Validate redirectPath
	// To prevent Open Redirect vulnerabilities, we must ensure the redirectPath 
	// is either a relative path (starts with / but not //) or matches our allowed domain.
	if !isValidRedirect(redirectPath) {
