	}

	// Option A: Check if it's a relative path (e.g., /dashboard)
	// We check for "/" but prevent "//" which some browsers interpret as a protocol-relative URL.
	if strings.HasPrefix(redirectURL, "/") && !strings.HasPrefix(redirectURL, "//") {
